// Validation
const ts = msg.payload && msg.payload.ts;
const values = msg.payload && msg.payload.values;

if (typeof ts !== "number") {
    msg.statusCode = 400;
    msg.payload = { status: "error", reason: "ts missing or not number" };
    return [null, null, msg];
}
if (typeof values !== "object" || values === null || Object.keys(values).length === 0) {
    msg.statusCode = 400;
    msg.payload = { status: "error", reason: "values missing or empty" };
    return [null, null, msg];
}

// PASO 2a: BUILD CONNECT MESSAGES (devices not seen yet)
const DEVICE_PROFILE = flow.get("DEVICE_PROFILE") || "sensor_planta";
const seen = flow.get("connectedDevices") || {};
const connectMsgs = [];

for (const tagName of Object.keys(values)) {
    if (!seen[tagName]) {
        connectMsgs.push({
            payload: JSON.stringify({ device: tagName, type: DEVICE_PROFILE }),
            topic: "v1/gateway/connect",
            qos: 1
        });
        seen[tagName] = true;
    }
}
flow.set("connectedDevices", seen);

// PASO 2b: BUILD GATEWAY MQTT TELEMETRY PAYLOAD
const gatewayPayload = {};
for (const [tag, value] of Object.entries(values)) {
    gatewayPayload[tag] = [{ ts: ts, values: { value: value } }];
}
const mqttMsg = {
    payload: JSON.stringify(gatewayPayload),
    topic: "v1/gateway/telemetry",
    qos: 1
};
const output1 = connectMsgs.length > 0
    ? [...connectMsgs, mqttMsg]
    : mqttMsg;

// PASO 3: BUILD ML INFERENCE MESSAGE (only if URL configured)
const mlUrl = flow.get("ML_INFERENCE_URL");
let mlMsg = null;
if (mlUrl) {
    mlMsg = {
        payload: { ts: ts, sensors: values },
        url: mlUrl,
        method: "POST",
        headers: { "Content-Type": "application/json" },
        requestTimeout: 5000
    };
}

// HTTP 200 ack (preserves req/res)
msg.statusCode = 200;
msg.payload = { status: "ok", tags: Object.keys(values).length };

return [output1, mlMsg, msg];

if (env.get("NR_ADMIN_ENABLED") !== "true") {
    msg.statusCode = 404;
    msg.headers = {
        "Content-Type": "text/html; charset=utf-8",
        "X-Content-Type-Options": "nosniff"
    };
    msg.payload = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="utf-8">\n<title>Error</title>\n</head>\n<body>\n<pre>Cannot ' + msg.req.method + ' ' + msg.req.url + '</pre>\n</body>\n</html>\n';
    return msg;
}
const url = msg.payload && msg.payload.url;
if (typeof url !== "string" || url.length === 0) {
    msg.statusCode = 400;
    msg.payload = { status: "error", reason: "url missing" };
    return msg;
}
flow.set("ML_INFERENCE_URL", url);
msg.statusCode = 200;
msg.payload = { status: "ok", url: url };
return msg;

if (env.get("NR_ADMIN_ENABLED") !== "true") {
    msg.statusCode = 404;
    msg.headers = {
        "Content-Type": "text/html; charset=utf-8",
        "X-Content-Type-Options": "nosniff"
    };
    msg.payload = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="utf-8">\n<title>Error</title>\n</head>\n<body>\n<pre>Cannot ' + msg.req.method + ' ' + msg.req.url + '</pre>\n</body>\n</html>\n';
    return msg;
}
flow.set("ML_INFERENCE_URL", undefined);
msg.statusCode = 200;
msg.payload = { status: "ok", cleared: true };
return msg;

if (env.get("NR_ADMIN_ENABLED") !== "true") {
    msg.statusCode = 404;
    msg.headers = {
        "Content-Type": "text/html; charset=utf-8",
        "X-Content-Type-Options": "nosniff"
    };
    msg.payload = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="utf-8">\n<title>Error</title>\n</head>\n<body>\n<pre>Cannot ' + msg.req.method + ' ' + msg.req.url + '</pre>\n</body>\n</html>\n';
    return msg;
}
msg.statusCode = 200;
msg.payload = { ML_INFERENCE_URL: flow.get("ML_INFERENCE_URL") || null };
return msg;
